```csharp
internal sealed class FulfillmentRefNoClient(IFulfillmentApiClient client, ILogger<FulfillmentRefNoClient> logger)
    : IFulfillmentRefNoClient
{
    public async Task<string?> ReadRefNoAsync(Guid fulfillmentOrderId, CancellationToken cancellationToken)
    {
        var response = await client.GetOrderAsync(fulfillmentOrderId, cancellationToken);
        return response?.Source.Ref;
    }
}
